enum custom_keycodes {
    SPL = SAFE_RANGE, //open copy of browser window, in another window
    PIPE, // ||
    PGUP_DBL, //2 page scroll up 
    PGDN_DBL, //2 page scroll down
    PAR, // ()
    CUR, // {}
    SQU, // []
    QUO, // ''
    DBLQUO, // ""
    CAPG, // G
    RARROW, // right arrow
    LARROW, // right arrow
    ML, //left mouse
    SWITCH_TAB, //ctrl + tab
    PREV_TAB, //ctrl + shift + tab
    ADD_BAR, //ctrl l
    NEW_TAB, //ctrl t
    CLOSE_TAB, //ctrl w
};

//define variables for customised tap-hold keys
#define PAR     LT(PAR, KC_0)   // () with arrow back function when held
#define CUR     LT(CUR, KC_0)   // {} with arrow back function when held
#define SQU     LT(SQU, KC_0)   // [] with arrow back function when held
#define QUO     LT(QUO, KC_0)   // '' with arrow back function when held
#define DBLQUO     LT(DBLQUO, KC_0)   // "" with arrow back function when held
#define PIPE     LT(PIPE, KC_0)   // || with arrow back function when held
#define ML     LT(ML, KC_0)   // || with arrow back function when held

bool process_record_user(uint16_t keycode, keyrecord_t *record) {
  switch (keycode) {
    case SPL:
    	if (record->event.pressed) {
	      tap_code16(LCTL(KC_L));
    	  tap_code16(LSFT(KC_ENT));
	      tap_code(KC_PGDN);
	    }
     	return false;
	    break;
    case PIPE: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("||" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("||");        
        return false;
      } 
      return false;
      break;
    case PGUP_DBL:
      if (record->event.pressed) {
        tap_code(KC_PGUP);
        tap_code(KC_PGUP);
        tap_code16(RGUI(KC_LEFT));
        tap_code(KC_PGUP);
        tap_code(KC_PGUP);
      }
      return false;
      break;
    case PGDN_DBL:
      if (record->event.pressed) {
        tap_code(KC_PGDN);
        tap_code(KC_PGDN);
        tap_code16(RGUI(KC_LEFT));
        tap_code(KC_PGDN);
        tap_code(KC_PGDN);
      }
      return false;
      break;
    //cancel rolled modifiers of same hand. Prevents modifiers accidental
    //press e.g. when press s and t key, stops ctrl + t behaviour.
    case LSFT_T(KC_T):
      if (record->event.pressed && record->tap.count > 0) {
        if (get_mods() & MOD_BIT(KC_LCTL)) {
          unregister_mods(MOD_BIT(KC_LCTL));
          tap_code(KC_S);
          tap_code(KC_T);
          add_mods(MOD_BIT(KC_LCTL));
          return false;
        }
      }
      return true;
     	break;
    case RSFT_T(KC_N):
      if (record->event.pressed && record->tap.count > 0) {
        if (get_mods() & MOD_BIT(KC_RCTL)) {
          unregister_mods(MOD_BIT(KC_RCTL));
          tap_code(KC_E);
          tap_code(KC_N);
          add_mods(MOD_BIT(KC_RCTL));
          return false;
        }
      }
      return true;
    	break;
    //enter goes back baselayer if layer set
    case KC_ENT:
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(3)
          || IS_LAYER_ON(4)) {
          tap_code(KC_ENT);
          layer_clear();       
          return false;
        }
      }
      return true;
      break;
    //clears all layers if access symbol layer
    case LT(3,KC_SPC):
      //when key held d
      if (!record->tap.count) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(4)) {
          layer_clear();       
          return true;
        }
      }
      return true;
      break;
    case LT(3,KC_BSPC):
      if (!record->tap.count) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(4)) {
          layer_clear();       
          return true;
        }
      }
      return true;
      break;
    case TO(4):
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2)) {
          layer_clear();       
          return true;
        }
      }
      return true;
      break;
    //escape goes back baselayer if layer set
    case KC_ESC:
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) || IS_LAYER_ON(2) || IS_LAYER_ON(4)) {
          layer_clear();       
          return false;
        }
      }
      return true;
      break;
    //macro for brackets
    case PAR: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("()" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("()");        
        return false;
      } 
      return false;
      break;
    case CUR:
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("{}" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("{}");        
        return false;
      } 
      return false;
      break;
    case SQU: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("[]" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("[]");        
        return false;
      } 
      return false;
      break;
    //below needs to be added to combos to use right pinky keys
    case QUO: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("''" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("''");        
        return false;
      } 
      return false;
      break;
    case DBLQUO: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("\"\"" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("\"\"");        
        return false;
      } 
      return false;
      break;
    case ML: 
      if (record->event.pressed) {
        if(record->tap.count == 2) {
          tap_code(MS_BTN1);
          layer_clear();
          return false;
        }
      return true;
      } 
      break;
    /*
    case  
   	  if(record->event.pressed) {
  	    if(get_mods() & MOD_BIT(KC_LSFT)) {
  	     	unregister_mods(MOD_BIT(KC_LSFT));	
  	      SEND_STRING("\"\"" SS_TAP(X_LEFT));
  		    add_mods(MOD_BIT(KC_LSFT));
  		    return false;
  	    //if no shift pressed
  	    } else {
  	      SEND_STRING("\"\""); 
  	    }
  	  } 
      return true;
	    break;
      */
    case CAPG: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RSFT));
        tap_code(KC_G);
        layer_clear();
        unregister_mods(MOD_BIT(KC_RSFT));
        return false;
  	  } 
      return true;
	    break;
    case NEW_TAB: 
   	  if(record->event.pressed) {
        layer_clear();
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_T);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
  	  } 
	    break;
    case CLOSE_TAB: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_W);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
  	  } 
	    break;
    case SWITCH_TAB: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_TAB);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
  	  } 
	    break;
    case PREV_TAB: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        register_mods(MOD_BIT(KC_RSFT));
        tap_code(KC_TAB);
        unregister_mods(MOD_BIT(KC_RCTL));
        unregister_mods(MOD_BIT(KC_RSFT));
        return false;
  	  } 
	    break;
    case ADD_BAR: 
   	  if(record->event.pressed) {
        layer_clear();
        SEND_STRING(SS_LCTL("l"));
        return false;
  	  } 
	    break;
    case RARROW: 
   	  if(record->event.pressed) {
        tap_code(KC_RGHT);
        return false;
  	  } 
      return true;
	    break;
    case LARROW: 
   	  if(record->event.pressed) {
        tap_code(KC_LEFT);
        return false;
  	  } 
      return true;
	    break;
  }
  return true;
};


